import React, { useEffect, useState } from "react";
import jsPDF from "jspdf";

import SplashScreen from "./screens/SplashScreen";
import SignInScreen from "./screens/SignInScreen";
import SignUpScreen from "./screens/SignInScreen";
import HomeScreen from "./screens/HomeScreen";
import DepositScreen from "./screens/DepositScreen";
import WithdrawScreen from "./screens/WithdrawScreen";
import ProfileScreen from "./screens/ProfileScreen";
import AddPaymentSourceScreen from "./screens/AddPaymentSourceScreen";

import TransactionsHistoryScreen from "./screens/TransactionHistoryScreen";
import TransactionReceiptScreen from "./screens/TransactionReceiptScreen";
import TransactionResultScreen from "./screens/TransactionResultScreen";

import ConfirmPaymentScreen from "./screens/ConfirmPaymentScreen";
import PaymentProcessingScreen from "./screens/PaymentProcessingScreen";
import PinScreen from "./screens/PinScreen";

import BottomNav from "./components/BottomNav";
import { generateReference } from "./helpers/reference";
import { CurrencyProvider } from "./context/CurrencyContext";

export default function App() {
  const [currentScreen, setCurrentScreen] = useState("Splash");
  const [activeTab, setActiveTab] = useState("home");
  const [darkMode, setDarkMode] = useState(false);

  const [user, setUser] = useState(null);
  const [transactions, setTransactions] = useState([]);
  const [selectedTransaction, setSelectedTransaction] = useState(null);

  const [pendingPayment, setPendingPayment] = useState(null);
  const [pendingAction, setPendingAction] = useState(null);
  const [requirePin, setRequirePin] = useState(false);
  const [transactionResult, setTransactionResult] = useState(null);

  /* ---------- LOAD STORAGE ---------- */
  useEffect(() => {
    const u = localStorage.getItem("user");
    const t = localStorage.getItem("transactions");
    if (u) setUser(JSON.parse(u));
    if (t) setTransactions(JSON.parse(t));
  }, []);

  /* ---------- SAVE STORAGE ---------- */
  useEffect(() => {
    if (user) localStorage.setItem("user", JSON.stringify(user));
    localStorage.setItem("transactions", JSON.stringify(transactions));
  }, [user, transactions]);

  /* ---------- NAV ---------- */
  const openScreen = (screen, data = null) => {
    if (screen === "TransactionReceipt") setSelectedTransaction(data);
    setCurrentScreen(screen);
  };

  const goHome = () => {
    setCurrentScreen("Main");
    setActiveTab("home");
  };

  const addTransaction = (tx) => {
    setTransactions((prev) => [tx, ...prev]);
  };

  const handlePinSuccess = () => {
    setRequirePin(false);
    if (typeof pendingAction === "function") pendingAction();
    setPendingAction(null);
  };

  /* ---------- SHARE ---------- */
  const handleShare = (tx) => {
    const text = `
Transaction Receipt
------------------
Amount: ₦${tx.amount}
Type: ${tx.type}
Reference: ${tx.reference}
Date: ${new Date(tx.date).toLocaleString()}
    `;
    navigator.share
      ? navigator.share({ title: "Transaction Receipt", text })
      : navigator.clipboard.writeText(text);
  };

  /* ---------- PDF ---------- */
  const handleDownload = (tx) => {
    const doc = new jsPDF();
    let y = 20;
    const success = tx.status === "success";

    const barColor = success ? [0, 135, 90] : [220, 38, 38];
    doc.setFillColor(...barColor);
    doc.rect(10, 10, 190, 8, "F");

    doc.setFontSize(18);
    doc.text("Transaction Receipt", 20, y);
    y += 20;

    const fields = [
      ["Amount", `₦${tx.amount}`],
      ["Type", tx.type],
      ["Reference", tx.reference],
      ["Date", new Date(tx.date).toLocaleString()],
      ["Status", success ? "Completed" : "Failed"],
    ];

    fields.forEach(([label, value]) => {
      doc.setFontSize(10);
      doc.text(`${label}:`, 20, y);
      doc.text(String(value), 70, y);
      y += 10;
    });

    doc.save(`receipt-${tx.reference}.pdf`);
  };

  return (
    <CurrencyProvider>
      <div className={`min-h-screen ${darkMode ? "bg-gray-900 text-white" : "bg-gray-50 text-gray-900"}`}>

        {currentScreen === "Main" && (
          <>
            {activeTab === "home" && (
              <HomeScreen
                user={user}
                transactions={transactions}
                darkMode={darkMode}
                toggleDarkMode={() => setDarkMode(d => !d)}
                openScreen={openScreen}
              />
            )}

            {activeTab === "profile" && (
              <ProfileScreen
                user={user}
                darkMode={darkMode}
                openScreen={openScreen}
              />
            )}

            <BottomNav
              active={activeTab}
              setActive={(tab) => { setActiveTab(tab); setCurrentScreen("Main"); }}
              darkMode={darkMode}
            />
          </>
        )}

        {/* ---------- PROCESSING (FIXED BALANCE LOGIC) ---------- */}
        {currentScreen === "PaymentProcessing" && pendingPayment && (
          <PaymentProcessingScreen
            darkMode={darkMode}
            onComplete={() => {
              const amount = Number(pendingPayment.amount);

              setUser(prev => {
                const balance = Number(prev?.balance || 0);
                const savings = Number(prev?.savings || 0);

                return {
                  ...prev,
                  balance:
                    pendingPayment.type === "save"
                      ? balance + amount
                      : balance - amount,
                  savings:
                    pendingPayment.type === "save"
                      ? savings + amount
                      : savings - amount,
                };
              });

              const tx = {
                id: Date.now(),
                reference: generateReference(),
                type: pendingPayment.type,
                amount,
                date: new Date().toISOString(),
                status: "success",
              };

              addTransaction(tx);
              setTransactionResult(tx);
              setPendingPayment(null);
              setCurrentScreen("TransactionResult");
            }}
          />
        )}

        {currentScreen === "TransactionResult" && transactionResult && (
          <TransactionResultScreen
            status="success"
            amount={transactionResult.amount}
            type={transactionResult.type}
            darkMode={darkMode}
            onDone={goHome}
          />
        )}

        {currentScreen === "TransactionReceipt" && selectedTransaction && (
          <TransactionReceiptScreen
            transaction={selectedTransaction}
            darkMode={darkMode}
            onShare={handleShare}
            onDownload={() => handleDownload(selectedTransaction)}
            onDone={goHome}
          />
        )}
      </div>
    </CurrencyProvider>
  );
}
